import React, { useState, useEffect, useRef } from 'react';
import { Camera, Map, Utensils, Info, Calendar, Sun, AlertTriangle, Wallet, Train, ChevronDown, ChevronUp, Star, Sparkles, Send, Volume2, Loader, Cloud, Thermometer, Snowflake, Navigation, Coins, ExternalLink, MessageCircle, Languages, X, LocateFixed, MapPin, Filter, CheckCircle, Check, Car, Hotel, Battery, BatteryCharging, Footprints, ArrowRight, Wrench, Ticket, Droplets, PartyPopper, Calculator, Gem, Sunrise, Sunset, Aperture } from 'lucide-react';

// --- MAIN APP COMPONENT ---
const App = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [weatherData, setWeatherData] = useState(null);
  const [aiContextPrompt, setAiContextPrompt] = useState('');

  // Fetch Weather logic
  useEffect(() => {
    const fetchWeather = async () => {
      try {
        // Coordenadas de Doha
        const response = await fetch('https://api.open-meteo.com/v1/forecast?latitude=25.28&longitude=51.53&current_weather=true&hourly=temperature_2m&daily=sunrise,sunset&timezone=Asia%2FQatar');
        const data = await response.json();
        setWeatherData(data);
      } catch (e) {
        console.error("Weather fetch failed", e);
        // Fallback a clima típico de Enero
        setWeatherData({ current_weather: { temperature: 22, weathercode: 0 } });
      }
    };
    fetchWeather();
    const interval = setInterval(fetchWeather, 21600000); // 6 horas
    return () => clearInterval(interval);
  }, []);

  // Handlers
  const handleLiveGuide = (placeName) => {
    setAiContextPrompt(`Estoy ahora mismo en ${placeName}. Actúa como mi guía turístico experto. ¿Qué detalles no debo perderme y cuál es el mejor ángulo para una foto?`);
    setActiveTab('ai');
  };

  const handleDiningConcierge = (craving) => {
    setAiContextPrompt(`Actúa como un conserje gastronómico de lujo en el St. Regis Doha. Tengo antojo de comida "${craving}". Recomiéndame las mejores opciones (prioriza las del hotel si son buenas o zonas cercanas como Katara).`);
    setActiveTab('ai');
  };

  const handlePlanB = (day, mainPlan, area) => {
    setAiContextPrompt(`Es el Día ${day} de mi viaje en Doha (Enero). Mi alojamiento es el St. Regis. El plan original era: ${mainPlan} (Zona: ${area}). Dame dos opciones alternativas rápidas (Cansado vs Animado).`);
    setActiveTab('ai');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'home': return <HomeView weather={weatherData} onPlanB={handlePlanB} />;
      case 'logistics': return <LogisticsView />;
      case 'ai': return <AIView initialPrompt={aiContextPrompt} clearPrompt={() => setAiContextPrompt('')} />;
      case 'explore': return <ExploreView onLiveGuide={handleLiveGuide} />;
      case 'dining': return <DiningView onConcierge={handleDiningConcierge} />;
      case 'tools': return <ToolsView />;
      case 'photo': return <PhotoView />;
      case 'metro': return <MetroPlannerView />;
      default: return <HomeView />;
    }
  };

  return (
    <div className="max-w-md mx-auto bg-gray-50 h-screen flex flex-col font-sans text-gray-800 overflow-hidden relative">
      {/* Header */}
      <div className="bg-white px-4 py-3 shadow-sm border-b border-gray-100 flex justify-between items-center z-10">
        <div>
          <h1 className="text-lg font-black tracking-tight text-teal-800">Doha: Guía Maestra</h1>
          <p className="text-[10px] font-medium text-gray-400">Edición St. Regis • Enero 2026</p>
        </div>
        <div className="bg-teal-50 px-2 py-1 rounded-full border border-teal-100">
           <span className="text-[10px] font-bold text-teal-700">v12.0 St.Regis</span>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 overflow-y-auto pb-20 scrollbar-hide">
        {renderContent()}
      </div>

      {/* Bottom Navigation */}
      <div className="bg-white border-t border-gray-200 px-4 py-2 flex justify-between items-center text-[10px] font-medium fixed bottom-0 w-full max-w-md z-50 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
        <NavItem icon={<Hotel size={20} />} label="Inicio" id="home" activeTab={activeTab} setActiveTab={setActiveTab} />
        <NavItem icon={<Map size={20} />} label="Visitas" id="explore" activeTab={activeTab} setActiveTab={setActiveTab} />
        <NavItem icon={<Sparkles size={24} className="text-white fill-current" />} label="IA" id="ai" activeTab={activeTab} setActiveTab={setActiveTab} isSpecial />
        <NavItem icon={<Utensils size={20} />} label="Comer" id="dining" activeTab={activeTab} setActiveTab={setActiveTab} />
        <NavItem icon={<Wrench size={20} />} label="Útiles" id="tools" activeTab={activeTab} setActiveTab={setActiveTab} />
      </div>
    </div>
  );
};

// --- HOME VIEW (Mejorada con lógica de Enero/Piscina) ---
const HomeView = ({ weather, onPlanB }) => {
  const temp = weather?.current_weather?.temperature || 22; // Default Enero
  const seaTemp = 20; // Temperatura mar en Enero (Fresco)

  // Lógica de baño para Enero
  let swimAdvice = "¡Piscina Climatizada!";
  let swimColor = "text-orange-600";

  if (temp > 26 && seaTemp > 22) {
      swimAdvice = "¡Día de Playa!";
      swimColor = "text-teal-600";
  } else if (temp < 18) {
      swimAdvice = "Solo Jacuzzi";
      swimColor = "text-red-600";
  }

  const itinerary = [
    { day: 1, zone: "Zona Norte", title: "Aclimatación: Katara", steps: ["Relax St. Regis", "Katara (Andando)", "Cena Boho Social"], walkable: true, walk_desc: "10-15 min a pie.", map_query: "The St. Regis Doha/Katara Cultural Village", desc: "Día tranquilo. Aprovechad el hotel y Katara." },
    { day: 2, zone: "Desierto", title: "Dunas y Viernes", steps: ["Mañana Piscina", "Safari 14:00h", "Mar Interior"], walkable: false, walk_desc: "Requiere 4x4.", map_query: "Sealine Beach Resort/Khor Al Adaid", desc: "El viernes todo cierra por la mañana. Safari por la tarde." },
    { day: 3, zone: "Zona Centro", title: "Historia y Zoco", steps: ["Museo Nacional", "Puerto Viejo (Mina)", "Souq Waqif"], walkable: true, walk_desc: "Metro Línea Oro.", map_query: "National Museum of Qatar/Old Doha Port/Souq Waqif", desc: "El día cultural fuerte. Cenad en el Zoco." },
    { day: 4, zone: "La Perla", title: "Venecia Árabe", steps: ["Msheireb (Mañana)", "Qanat Quartier", "Porto Arabia"], walkable: true, walk_desc: "Uber a The Pearl.", map_query: "Msheireb Downtown Doha/Qanat Quartier", desc: "Fotos en el barrio de colores y canales." },
    { day: 5, zone: "Arte", title: "Museos y Skyline", steps: ["Museo Arte Islámico", "MIA Park", "Cena Nobu"], walkable: true, walk_desc: "Paseo Corniche.", map_query: "Museum of Islamic Art/MIA Park/Nobu Doha", desc: "Mejores vistas del skyline desde el parque." },
    { day: 6, zone: "Shopping", title: "Lujo Moderno", steps: ["Place Vendôme", "Fuentes Lusail", "Katara Towers"], walkable: true, walk_desc: "Uber o Metro.", map_query: "Place Vendôme Mall/Lusail Marina Promenade", desc: "Ver las fuentes danzantes y el lujo de Lusail." },
    { day: 7, zone: "Relax", title: "Despedida", steps: ["Piscina St. Regis", "Check-out", "Aeropuerto"], walkable: false, walk_desc: "Taxi.", map_query: "The St. Regis Doha/Hamad International Airport", desc: "Disfrutad del aeropuerto (The Orchard) antes de volar." }
  ];

  return (
    <div className="p-4 space-y-6 pb-20">
      {/* Weather Card */}
      <div className="bg-gradient-to-br from-blue-500 to-blue-600 rounded-2xl p-5 text-white shadow-lg relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-20"><Cloud size={80} /></div>
        <div className="relative z-10">
          <p className="text-blue-100 text-xs font-bold uppercase tracking-wider mb-1">Doha, Qatar (Ene 7-14)</p>
          <div className="flex items-end gap-2 mb-2">
             <h2 className="text-5xl font-black tracking-tighter">{Math.round(temp)}°C</h2>
             <span className="mb-2 text-lg font-medium opacity-90">Soleado</span>
          </div>
          <div className="flex gap-3 text-xs font-medium bg-white/20 p-2 rounded-lg backdrop-blur-sm w-fit">
             <span className="flex items-center gap-1"><Navigation size={12}/> Viento suave</span>
             <span className="flex items-center gap-1"><Sun size={12}/> UV Medio</span>
          </div>
        </div>
      </div>

      {/* BEACH/POOL MONITOR IMPROVED */}
      <div className="bg-white p-3 rounded-xl shadow-sm border border-blue-100">
        <div className="flex justify-between items-center mb-1">
          <span className="text-xs font-bold text-gray-500 uppercase tracking-wider">Estado del Baño</span>
          <Thermometer size={14} className="text-blue-400"/>
        </div>
        <div className="flex items-center gap-4">
          <div>
             <p className="text-2xl font-black text-gray-800">{Math.round(temp)}°C</p>
             <p className="text-[10px] text-gray-400">Aire</p>
          </div>
          <div className="h-8 w-px bg-gray-200"></div>
          <div>
             <p className="text-sm font-bold text-blue-600">~{seaTemp}°C</p>
             <p className="text-[10px] text-gray-400">Mar (Fresco)</p>
          </div>
          <div className="ml-auto text-right">
             <p className={`text-sm font-black ${swimColor}`}>{swimAdvice}</p>
             <p className="text-[10px] text-gray-400">Tu mejor opción hoy</p>
          </div>
        </div>
      </div>

      {/* Itinerary */}
      <div>
        <h3 className="font-bold text-gray-800 mb-3 flex items-center gap-2">
           <Calendar size={18} className="text-teal-600"/> Itinerario "Sin Estrés"
        </h3>
        <div className="space-y-3">
          {itinerary.map((item, idx) => (
            <div key={idx} className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-all relative group">
               <div className="absolute top-4 right-4 text-xs font-bold text-gray-300">D{item.day}</div>
               <h4 className="font-bold text-gray-800 text-lg mb-1">{item.title}</h4>
               <p className="text-xs font-semibold text-teal-600 uppercase tracking-wide mb-3">{item.zone}</p>

               <div className="flex flex-wrap gap-2 mb-3">
                 {item.steps.map((step, sIdx) => (
                   <div key={sIdx} className="flex items-center text-xs text-gray-600 bg-gray-50 px-2 py-1 rounded border border-gray-200">
                      {step}
                      {sIdx < item.steps.length - 1 && <ArrowRight size={10} className="ml-1 text-gray-400"/>}
                   </div>
                 ))}
               </div>

               <p className="text-xs text-gray-500 italic border-l-2 border-gray-200 pl-2 mb-3">{item.desc}</p>

               <div className="flex gap-2 mt-2">
                 <button onClick={() => window.open(`https://www.google.com/maps/dir/${item.map_query}`, '_blank')} className="flex items-center gap-1.5 px-3 py-2 bg-blue-50 text-blue-600 rounded-lg text-xs font-bold hover:bg-blue-100 transition-colors flex-1 justify-center">
                    <Map size={14}/> Ver Ruta
                 </button>
                 <button onClick={() => onPlanB(item.day, item.title, item.zone)} className="px-3 py-2 bg-amber-50 text-amber-600 rounded-lg text-xs font-bold hover:bg-amber-100 transition-colors flex-1 justify-center">
                    <Sparkles size={14}/> Plan B
                 </button>
               </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

// --- LOGISTICS VIEW (Con botón de pánico St. Regis) ---
const LogisticsView = () => (
  <div className="p-4 space-y-4 pb-24">
     {/* Tarjeta de Hotel para Taxistas */}
     <div className="bg-amber-50 p-5 rounded-xl border border-amber-200 shadow-sm">
        <h3 className="font-bold text-amber-800 flex items-center gap-2 mb-2">
           <Hotel size={16}/> Tu Dirección (Enséñalo al Taxi)
        </h3>
        <div className="bg-white p-4 rounded-lg border border-amber-100">
            <p className="text-3xl font-black text-right mt-1 font-serif text-amber-950 leading-relaxed">
            فندق سانت ريجيس الدوحة
            </p>
            <p className="text-lg text-right text-gray-500 font-serif">Al Qassar</p>
        </div>
        <p className="text-xs text-center mt-3 text-amber-700 font-medium">The St. Regis Doha</p>
     </div>

     <SectionHeader title="Esenciales" subtitle="Normas y Transporte" />
     <Accordion title="Códigos de Vestimenta" icon={<CheckCircle size={18} className="text-teal-600"/>}>
        <ul className="text-sm space-y-2 p-2 text-gray-600">
           <li>• <b>General:</b> Hombros y rodillas cubiertos.</li>
           <li>• <b>St. Regis (Piscina):</b> Bikini permitido.</li>
           <li>• <b>Katara/Zoco:</b> Más conservador. Pashmina a mano.</li>
        </ul>
     </Accordion>

     <Accordion title="Trucos de Metro (Gold Club)" icon={<Train size={18} className="text-teal-600"/>}>
        <div className="text-sm text-gray-600 p-2 space-y-2">
           <p>Tu estación es <b>Al Qassar (Línea Roja)</b>.</p>
           <p>Compra la tarjeta <b>"Gold Club"</b> (Vagón VIP).</p>
           <p>• Coste: 100 QAR tarjeta + 10 QAR viaje.</p>
           <p>• Ventaja: Asientos de cuero, vacío y cómodo.</p>
        </div>
     </Accordion>

     <Accordion title="Taxis & Uber" icon={<Car size={18} className="text-teal-600"/>}>
        <div className="text-sm text-gray-600 p-2 space-y-2">
           <p>• <b>Uber:</b> Funciona perfecto. Úsalo para distancias cortas.</p>
           <p>• <b>Karwa (Turquesa):</b> Taxis oficiales. Baratos y aceptan tarjeta.</p>
           <p>• <b>Tip:</b> A la salida de los malls, busca la zona "Uber/Taxi pickup".</p>
        </div>
     </Accordion>
  </div>
);

// --- AI VIEW (Personalizada para Enero 2026) ---
const AIView = ({ initialPrompt, clearPrompt }) => {
  const [query, setQuery] = useState('');
  const [messages, setMessages] = useState([
    { role: 'assistant', text: '¡Hola! Soy tu guía del St. Regis. Pregúntame sobre horarios, reservas o traduce frases al árabe.' }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [showTranslator, setShowTranslator] = useState(false);
  const [translationMode, setTranslationMode] = useState(null);
  const messagesEndRef = useRef(null);
  const hasAutoSent = useRef(false);

  const scrollToBottom = () => { messagesEndRef.current?.scrollIntoView({ behavior: "smooth" }); };
  useEffect(() => { scrollToBottom(); }, [messages]);
  useEffect(() => { if (initialPrompt && !hasAutoSent.current) { handleSend(initialPrompt); hasAutoSent.current = true; clearPrompt(); } }, [initialPrompt]);

  const handleSend = async (textOverride = null) => {
    const textToSend = textOverride || query;
    if (!textToSend.trim()) return;

    let systemPrompt = `
      Actúa como un guía turístico local experto en Doha, Catar.
      CONTEXTO DEL VIAJERO:
      - Alojamiento: The St. Regis Doha (Al Qassar).
      - Fechas: 7-14 Enero 2026 (Invierno, clima fresco por la noche).
      - Estilo: Pareja adulta, presupuesto medio-alto pero buscan valor.
      - Intereses: Fotografía, Gastronomía, Relax.

      TU PERSONALIDAD:
      - Respuestas rápidas y concisas (máximo 3 frases si es posible).
      - Da "perlas" informativas y trucos locales.
      - Si preguntan por baño, recomienda la piscina climatizada del hotel (28°C) sobre el mar (19°C).
      - Si es viernes mañana, recuerda que todo está cerrado hasta las 13:00.
    `;

    let userDisplayRole = 'user';

    if (translationMode) {
      userDisplayRole = 'translator-user';
      if (translationMode === 'es-ar') systemPrompt = "Traduce Español a Árabe Catarí (Dialecto del Golfo). Incluye fonética simple.";
      if (translationMode === 'es-en') systemPrompt = "Traduce Español a Inglés.";
    }

    const userMsg = { role: userDisplayRole, text: textToSend, mode: translationMode };
    setMessages(prev => [...prev, userMsg]);
    if (!textOverride) setQuery('');

    setIsLoading(true);

    try {
      // ⚠️ AQUÍ PONES TU API KEY
      const apiKey = ""; 

      const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-preview-09-2025:generateContent?key=${apiKey}`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ contents: [{ parts: [{ text: textToSend }] }], systemInstruction: { parts: [{ text: systemPrompt }] } })
      });

      const data = await response.json();
      const aiText = data.candidates?.?.content?.parts?.?.text || "Error. Revisa tu API Key.";
      setMessages(prev => [...prev, { role: 'assistant', text: aiText, isTranslation: !!translationMode }]);
    } catch (error) { setMessages(prev => [...prev, { role: 'assistant', text: "Error de conexión." }]); } finally { setIsLoading(false); }
  };

  return (
    <div className="flex flex-col h-full bg-gray-50">
      <div className={`flex items-center justify-between p-3 border-b border-gray-200 ${translationMode ? 'bg-indigo-600 text-white' : 'bg-white text-gray-700'}`}>
         <div className="flex items-center gap-2">
            {translationMode ? <Languages size={18}/> : <Sparkles size={18} className="text-amber-500"/>}
            <span className="font-bold text-sm">{translationMode ? "Modo Traductor" : "Asistente St. Regis"}</span>
         </div>
         {translationMode && (<button onClick={() => setTranslationMode(null)} className="bg-white/20 p-1 rounded-full"><X size={14}/></button>)}
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role.includes('user') ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl px-4 py-3 text-sm shadow-sm ${msg.role.includes('user') ? (msg.mode ? 'bg-indigo-100 text-indigo-900' : 'bg-teal-600 text-white') : 'bg-white border border-gray-100 text-gray-800'}`}>
              <p className="whitespace-pre-wrap leading-relaxed">{msg.text}</p>
            </div>
          </div>
        ))}
        {isLoading && <div className="flex items-center gap-2 text-xs text-gray-400 p-2"><Loader size={12} className="animate-spin"/> Pensando...</div>}
        <div ref={messagesEndRef} />
      </div>

      <div className="p-3 bg-white border-t border-gray-200">
        {showTranslator && (
          <div className="flex gap-2 mb-3 overflow-x-auto pb-1">
             <button onClick={() => { setTranslationMode('es-ar'); setShowTranslator(false); }} className="px-3 py-2 bg-indigo-50 text-indigo-700 rounded-lg text-xs font-bold border border-indigo-100">🇪🇸 ➡ 🇶🇦 Árabe</button>
             <button onClick={() => { setTranslationMode('es-en'); setShowTranslator(false); }} className="px-3 py-2 bg-indigo-50 text-indigo-700 rounded-lg text-xs font-bold border border-indigo-100">🇪🇸 ➡ 🇬🇧 Inglés</button>
          </div>
        )}
        <div className="flex items-center gap-2 bg-gray-100 p-1.5 rounded-full border border-gray-200 focus-within:ring-2 focus-within:ring-teal-500/20 focus-within:border-teal-500 transition-all">
          <button onClick={() => setShowTranslator(!showTranslator)} className={`p-2 rounded-full transition-colors ${translationMode ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:bg-gray-200'}`}><Languages size={18}/></button>
          <input type="text" value={query} onChange={(e) => setQuery(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleSend()} placeholder={translationMode ? "Escribe para traducir..." : "Pregunta sobre tu viaje..."} className="flex-1 bg-transparent border-none outline-none text-sm px-2 text-gray-700 placeholder-gray-400" />
          <button onClick={() => handleSend()} disabled={!query.trim() || isLoading} className={`p-2 rounded-full text-white shadow-sm transition-transform active:scale-95 ${translationMode ? 'bg-indigo-600' : 'bg-teal-600'}`}><Send size={18}/></button>
        </div>
      </div>
    </div>
  );
};

// --- DINING VIEW (Actualizada con St. Regis prioritario) ---
const DiningView = ({ onConcierge }) => {
  const [filter, setFilter] = useState('Todos');
  const [sortByGeo, setSortByGeo] = useState(false);
  const [isLocating, setIsLocating] = useState(false);

  // Lista de Restaurantes (Incluyendo los del St. Regis con dist 0.0)
  const allRestaurants = [
    // ST. REGIS (BASE)
    { name: "Hakkasan", type: "Asiática", sub: "Cantonés Michelin", price: "$$$$", rating: 4.9, loc: "St. Regis Doha", dist: 0.0, img: "🥢" },
    { name: "Bebabel", type: "Árabe", sub: "Libanés Chic", price: "$$", rating: 4.6, loc: "St. Regis Doha", dist: 0.0, img: "🇱🇧" },
    { name: "Astor Grill", type: "Carnes", sub: "Steakhouse NY", price: "$$$", rating: 4.7, loc: "St. Regis Doha", dist: 0.0, img: "🥩" },
    { name: "BiBo", type: "Europea", sub: "Tapas Dani García", price: "$$$", rating: 4.6, loc: "St. Regis Doha", dist: 0.0, img: "🇪🇸" },
    { name: "Opal", type: "Europea", sub: "Gordon Ramsay", price: "$$$", rating: 4.5, loc: "St. Regis Doha", dist: 0.0, img: "👨‍🍳" },

    // EXTERIORES
    { name: "Chapati & Karak", type: "Económico", sub: "Snack Clásico", price: "$", rating: 4.8, loc: "Katara", dist: 1.2, img: "🫖" },
    { name: "Boho Social", type: "Internacional", sub: "Vistas al Mar", price: "$$$", rating: 4.7, loc: "Katara", dist: 1.5, img: "🌅" },
    { name: "Nobu Doha", type: "Asiática", sub: "Japonés Panorámico", price: "$$$$", rating: 4.9, loc: "Four Seasons", dist: 4.0, img: "🍣" },
    { name: "Parisa", type: "Árabe", sub: "Persa (Palacio)", price: "$$$", rating: 4.9, loc: "Souq Waqif", dist: 9.5, img: "✨" },
    { name: "Damasca One", type: "Árabe", sub: "Siria (Terraza)", price: "$$", rating: 4.6, loc: "Souq Waqif", dist: 9.5, img: "🥙" },
    { name: "Jiwan", type: "Árabe", sub: "Qatarí Moderno", price: "$$$$", rating: 4.8, loc: "Museo Nacional", dist: 10.5, img: "🇶🇦" },
    { name: "Turkey Central", type: "Económico", sub: "Kebabs Baratos", price: "$", rating: 4.9, loc: "Al Mirqab", dist: 12.0, img: "🌯" },
  ];

  const handleGeoSort = () => { setIsLocating(true); setTimeout(() => { setSortByGeo(true); setIsLocating(false); }, 1000); };

  const filteredList = allRestaurants
    .filter(r => filter === 'Todos' || r.type === filter)
    .sort((a, b) => {
      if (sortByGeo) {
         // St Regis siempre primero
         if (a.dist === 0) return -1;
         if (b.dist === 0) return 1;
         return a.dist - b.dist;
      }
      return b.rating - a.rating;
    });

