const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("API_KEY not found in environment variables");
    throw new Error("API Key missing");
  }
  return new GoogleGenAI({ apiKey });
};

export const generateStream = async (
  prompt: string,
  onChunk: (text: string) => void
) => {
  try {
    const ai = getClient();

    // We use the Thinking model for complex clinical reasoning if available, 
    // otherwise fallback to a standard preview model.
    // Based on guidelines, gemini-3-pro-preview is good for complex tasks.
    const modelId = "gemini-3-pro-preview";

    const responseStream = await ai.models.generateContentStream({
      model: modelId,
      contents: [
        {
          role: 'user',
          parts: [{ text: prompt }]
        }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.2, // Low temperature for clinical precision
      },
    });

    for await (const chunk of responseStream) {
      const text = chunk.text;
      if (text) {
        onChunk(text);
      }
    }
  } catch (error) {
    console.error("Error generating content:", error);
    onChunk("\n\n**ERROR DEL SISTEMA:** No se pudo conectar con el motor de IA. Verifique su conexión o clave API.");
  }
};

