// Simple formatter to handle bold, headers, and bullets without heavy markdown library
const formatMessage = (text: string) => {
  if (!text) return null;
  return text.split('\n').map((line, i) => {
    // Headers
    if (line.startsWith('### ')) return <h3 key={i} className="text-teal-700 font-bold text-md mt-2 mb-1">{line.replace('### ', '')}</h3>;
    if (line.startsWith('**') && line.endsWith('**')) return <strong key={i} className="block mt-2 mb-1 text-slate-900">{line.replace(/\*\*/g, '')}</strong>;

    // Lists
    if (line.trim().startsWith('- ')) return <div key={i} className="flex gap-2 ml-1"><span className="text-teal-500">•</span><span>{renderInlineStyles(line.replace('- ', ''))}</span></div>;

    // Empty lines
    if (!line.trim()) return <div key={i} className="h-2"></div>;

    return <p key={i} className="text-slate-700">{renderInlineStyles(line)}</p>;
  });
};

const renderInlineStyles = (text: string) => {
  const parts = text.split(/(\*\*.*?\*\*|🟢|🟡|🔴)/g);
  return parts.map((part, index) => {
    if (part.startsWith('**') && part.endsWith('**')) {
      return <strong key={index} className="font-bold text-slate-900">{part.replace(/\*\*/g, '')}</strong>;
    }
    if (part === '🟢') return <span key={index} className="mr-1">🟢</span>;
    if (part === '🟡') return <span key={index} className="mr-1">🟡</span>;
    if (part === '🔴') return <span key={index} className="mr-1">🔴</span>;
    return part;
  });
};

import React, { useState } from 'react';
import { Bot, Calculator, Settings, Stethoscope, Menu, X } from 'lucide-react';
import { ChatInterface } from './components/ChatInterface';
import { ToolsArea } from './components/ToolsArea';
import { AppMode, Message, MessageRole, CalculatorResult } from './types';
import { generateStream } from './services/geminiService';

export default function App() {
  const [mode, setMode] = useState<AppMode>(AppMode.CHAT);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  // Function to handle sending messages to Gemini
  const handleSendMessage = async (text: string) => {
    const newMessage: Message = {
      id: Date.now().toString(),
      role: MessageRole.USER,
      content: text,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, newMessage]);
    setIsLoading(true);

    const responseId = (Date.now() + 1).toString();
    // Placeholder for stream
    setMessages(prev => [...prev, {
      id: responseId,
      role: MessageRole.MODEL,
      content: '',
      timestamp: new Date(),
      isStreaming: true
    }]);

    let fullResponse = '';

    await generateStream(text, (chunk) => {
      fullResponse += chunk;
      setMessages(prev => prev.map(msg => 
        msg.id === responseId 
          ? { ...msg, content: fullResponse } 
          : msg
      ));
    });

    setMessages(prev => prev.map(msg => 
      msg.id === responseId 
        ? { ...msg, isStreaming: false } 
        : msg
    ));
    setIsLoading(false);
  };

  const handleCalculatorResult = (result: CalculatorResult) => {
    setMode(AppMode.CHAT);
    const prompt = `He calculado un ${result.name} con resultado: ${result.score}. ${result.details}. Interpretación: ${result.interpretation}. Dame recomendaciones clínicas breves basadas en Guías EAU para este perfil de paciente.`;
    handleSendMessage(prompt);
  };

  return (
    <div className="flex h-screen bg-slate-100 font-sans overflow-hidden">
      {/* Sidebar (Mobile Overlay & Desktop Static) */}
      <div className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-900 text-slate-300 transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="p-4 flex items-center justify-between border-b border-slate-800">
          <div className="flex items-center gap-2 font-bold text-white">
            <Stethoscope className="w-6 h-6 text-teal-500" />
            <span>URO-MASTER AI</span>
          </div>
          <button onClick={() => setIsSidebarOpen(false)} className="md:hidden text-slate-400">
            <X className="w-6 h-6" />
          </button>
        </div>

        <nav className="p-4 space-y-2">
          <NavItem 
            icon={<Bot />} 
            label="Asistente Clínico" 
            isActive={mode === AppMode.CHAT} 
            onClick={() => { setMode(AppMode.CHAT); setIsSidebarOpen(false); }} 
          />
          <NavItem 
            icon={<Calculator />} 
            label="Calculadoras" 
            isActive={mode === AppMode.TOOLS} 
            onClick={() => { setMode(AppMode.TOOLS); setIsSidebarOpen(false); }} 
          />
          <div className="pt-4 mt-4 border-t border-slate-800">
             <div className="px-4 py-2 text-xs font-semibold text-slate-500 uppercase tracking-wider">
               Sistema
             </div>
             <div className="px-4 py-2 text-xs text-slate-500">
               v3.0.1 (Stable)<br/>
               Protocolos: EAU 2024
             </div>
          </div>
        </nav>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col relative w-full">
        {/* Mobile Header */}
        <div className="md:hidden bg-white border-b border-slate-200 p-4 flex items-center justify-between">
           <button onClick={() => setIsSidebarOpen(true)} className="text-slate-600">
             <Menu className="w-6 h-6" />
           </button>
           <span className="font-bold text-slate-800">
             {mode === AppMode.CHAT ? 'Asistente Clínico' : 'Herramientas'}
           </span>
           <div className="w-6" /> {/* Spacer */}
        </div>

        <div className="flex-1 overflow-hidden relative">
          {mode === AppMode.CHAT ? (
            <ChatInterface 
              messages={messages} 
              onSendMessage={handleSendMessage} 
              isLoading={isLoading} 
            />
          ) : (
            <ToolsArea onResultGenerated={handleCalculatorResult} />
          )}
        </div>
      </div>
    </div>
  );
}

const NavItem = ({ icon, label, isActive, onClick }: any) => (
  <button
    onClick={onClick}
    className={`flex items-center gap-3 w-full px-4 py-3 rounded-lg transition-all duration-200 ${
      isActive 
        ? 'bg-teal-600 text-white shadow-lg shadow-teal-900/20' 
        : 'hover:bg-slate-800 text-slate-400 hover:text-white'
    }`}
  >
